// ---------- Helpers ----------

const blendGradient = (colors, angle = 120) =>
  colors.length > 1 ? `linear-gradient(${angle}deg, ${colors.join(", ")})` : colors[0] || T.line;

const colorOf = (name) => INTERESTS.find((i) => i.name === name)?.color || T.gray;

const missionFor = (selected) =>
  `Create something that blends ${selected[0]} and ${selected[1]}, and share it with at least 10 people.`;

const groupNameFor = (selected) => `The ${selected[0].split(" ")[0]} × ${selected[1].split(" ")[0]} Lab`;

