function Blending({ selected }) {
  const colors = selected.map(colorOf);
  return (
    <div className="flex flex-col items-center justify-center px-8 text-center" style={{ height: "100%" }}>
      <div className="relative mb-10" style={{ width: 140, height: 140 }}>
        {colors.slice(0, 5).map((c, idx) => (
          <div
            key={idx}
            className="absolute rounded-full swirl"
            style={{
              width: 70, height: 70, background: c, opacity: 0.85,
              top: 35 + 30 * Math.sin((idx / colors.length) * 6.28),
              left: 35 + 30 * Math.cos((idx / colors.length) * 6.28),
              animationDelay: `${idx * 0.15}s`,
              mixBlendMode: "multiply",
            }}
          />
        ))}
      </div>
      <h2 className="text-2xl mb-2" style={{ fontFamily: "'Fraunces', serif", color: T.ink }}>
        Blending your interests…
      </h2>
      <p className="text-sm" style={{ color: T.gray }}>
        Matching you with 4 peers and assigning your first mission
      </p>
    </div>
  );
}

