// ---------- App shell ----------

function AppShell({ selected, onReblend }) {
  const [nav, setNav] = useState("home");
  const [sprintJoined, setSprintJoined] = useState(false);
  const [missionDone, setMissionDone] = useState(false);
  const [celebrate, setCelebrate] = useState(false);

  const completeMission = () => {
    setMissionDone(true);
    setCelebrate(true);
  };

  const NAV = [
    { key: "home", label: "Home", Icon: HomeIcon },
    { key: "group", label: "My Group", Icon: Users },
    { key: "discover", label: "Discover", Icon: Compass },
    { key: "profile", label: "Profile", Icon: UserIcon },
  ];

  return (
    <div className="flex flex-col" style={{ height: "100%" }}>
      {celebrate && (
        <Celebration
          onSeeDiscover={() => { setCelebrate(false); setNav("discover"); }}
          onClose={() => setCelebrate(false)}
        />
      )}
      <div className="bl-phonescroll" style={{ background: T.sageMist }}>
        {nav === "home" && (
          <HomeScreen selected={selected} goTo={setNav} sprintJoined={sprintJoined} joinSprint={() => setSprintJoined(true)} missionDone={missionDone} />
        )}
        {nav === "group" && <GroupScreen selected={selected} missionDone={missionDone} completeMission={completeMission} />}
        {nav === "discover" && <DiscoverScreen selected={selected} missionDone={missionDone} />}
        {nav === "profile" && <ProfileScreen selected={selected} onReblend={onReblend} missionDone={missionDone} />}
      </div>

      <div
        className="bl-phonenav flex border-t"
        style={{ background: T.card, borderColor: T.line }}
      >
        {NAV.map(({ key, label, Icon }) => (
          <button
            key={key}
            onClick={() => setNav(key)}
            className="flex-1 py-2.5 flex flex-col items-center gap-0.5 active:scale-95 transition-transform"
          >
            <Icon size={20} style={{ color: nav === key ? T.sageDeep : T.faint }} />
            <span className="font-bold" style={{ fontSize: 10, color: nav === key ? T.sageDeep : T.faint }}>
              {label}
            </span>
          </button>
        ))}
      </div>
    </div>
  );
}

