function BoardPage({ boardUrl }) {
  const roles = [
    ["Safety & moderation", "Review reports and keep groups respectful."],
    ["Missions & community", "Help groups pick projects and hit their deadlines."],
    ["Partnerships & outreach", "Bring in schools, clubs, and sponsors."],
    ["Design & product", "Shape how Blendi looks and works."],
  ];
  return (
    <div className="bl-page">
      <div className="bl-wrap" style={{ maxWidth: 720 }}>
        <p className="bl-kicker" style={{ textAlign: "left" }}>Board application</p>
        <h1 className="bl-pagetitle">Join the Blendi Board</h1>
        <p className="bl-prose">The Blendi Board is the small team that runs Blendi, moderating groups, guiding missions, and keeping the platform safe. We're looking for 4 individuals to join as founding board members.</p>
        <p className="bl-prose">This is a big leadership role. Board members work directly with the CEO of Blendi, helping shape the platform from the very start and making sure the first groups actually work.</p>

        <h2 className="bl-pagesub">Where Blendi is headed</h2>
        <p className="bl-prose">Right now, Blendi is a platform built to help individuals find people to build with. In the near future, we plan to grow it into more of a business: applying for grants, working with sponsors, and building toward the kind of reach platforms like TikTok or LinkedIn have. Joining the board now is a chance to be part of that growth from the start, building something, leading something, and helping shape what it becomes.</p>
        <p className="bl-prose">We want Blendi to be a place where any kind of project can start. Some of those projects will be about advocacy, and part of the board's role will be helping groups find ways to advocate for causes they care about without running into avoidable problems along the way.</p>
        <p className="bl-prose">We're also thinking about how groups and projects could connect with each other more, beyond Discover, in ways that stay true to Blendi's values: no follower counts, no popularity contests, just real work finding its way to people who'd appreciate it. That's something we want to get right once Blendi is further along, and board members will help shape what that looks like.</p>

        <h2 className="bl-pagesub">What board members do</h2>
        <div className="bl-rolelist">
          {roles.map(([t, b]) => (
            <div key={t} className="bl-role">
              <p className="bl-roletitle">{t}</p>
              <p className="bl-prose" style={{ margin: 0 }}>{b}</p>
            </div>
          ))}
        </div>

        <h2 className="bl-pagesub">Time commitment</h2>
        <p className="bl-prose">This is a real commitment, not a small one. The full board meets with the CEO 2 to 4 times a week to discuss what's going on and where things are headed. It takes consistency and discipline to keep up with that, and the role grows as Blendi grows.</p>

        <h2 className="bl-pagesub">Who this is for</h2>
        <p className="bl-prose">You don't need a specific background or interest to apply. Anyone can be a leader, no matter what they're passionate about, and that's exactly the kind of person we're looking for: someone who shows up, follows through, and wants to help lead something from the ground up.</p>

        <h2 className="bl-pagesub">What happens after you apply</h2>
        <p className="bl-prose">After you submit the form, shortlisted applicants will be invited to a short interview, usually within about 1 to 2 weeks. We're looking for people who care about the idea and follow through, not necessarily experience.</p>

        <a href={boardUrl} target="_blank" rel="noopener noreferrer" className="bl-primary" style={{ textDecoration: "none", display: "inline-block", marginTop: 8 }}>Apply for the board</a>
        <p className="bl-fine" style={{ marginTop: 18 }}>This page comes down once the board is full.</p>
      </div>
    </div>
  );
}

